#include <iostream>
#include <string>

using namespace std;

string s = "";
string t = "";

char findTheDifference(string s, string t){
    char result;
    for(char c : s){
        result ^= c;
    }
    for(char c : t){
        result ^= c;
    }
    return result;
}

int main(){
    cout<<findTheDifference(s,t);
    return 0;
}